// Webhook signature verification — adapts to CRM provider
const provider = $env.CRM_PROVIDER || 'activix';
const input = $input.first().json;
const rawBody = $input.first().json.body ? JSON.stringify($input.first().json.body) : '';

if (provider === 'ghl') {
  // GHL uses a simple API key check or OAuth — no HMAC
  // Verify the request comes from GHL by checking known fields
  const body = input.body || input;
  if (!body.contactId && !body.contact_id && !body.id) {
    throw new Error('Invalid GHL webhook payload: no contact identifier found');
  }
  return [{ json: { ...input, _verified: true, _provider: 'ghl' } }];
}

// Default: Activix HMAC-SHA256 signature check
const crypto = require('crypto');
const secret = $env.ACTIVIX_WEBHOOK_SECRET || '';
const signature = input.headers?.['x-activix-webhook-signature'] || '';
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');

if (!signature || signature !== expected) {
  throw new Error('HMAC signature verification failed — returning 401');
}

return [{ json: { ...input, _verified: true, _provider: 'activix' } }];

// Parse lead data from any CRM into normalized format
const provider = $env.CRM_PROVIDER || 'activix';
const input = $input.first().json;
const body = input.body || input;

// Normalized lead format
let lead = {
  id: null,
  firstName: null,
  lastName: null,
  email: null,
  phone: null,
  phones: [],
  emails: [],
  locale: null,
  source: null,
  type: null,
  postalCode: null,
  vehicles: [],
  advisor: null,
  consentType: 'implied',
  consentDate: null,
  unsubscribeAll: false,
  unsubscribeSms: false,
  unsubscribeEmail: false,
  _provider: provider,
  _raw: body,
};

if (provider === 'ghl') {
  const contact = body.contact || body;
  lead.id = contact.id || contact.contactId || null;
  lead.firstName = contact.firstName || contact.first_name || contact.name?.split(' ')[0] || null;
  lead.lastName = contact.lastName || contact.last_name || contact.name?.split(' ').slice(1).join(' ') || null;
  lead.email = contact.email || null;
  lead.phone = contact.phone || null;
  lead.phones = contact.phone ? [{ number: contact.phone, type: 'mobile' }] : [];
  lead.emails = contact.email ? [{ address: contact.email, type: 'primary' }] : [];
  lead.locale = contact.tags?.includes('french') ? 'fr-CA' : null;
  lead.source = contact.source || contact.attributionSource?.medium || 'web';
  lead.type = contact.type || 'web';
  lead.postalCode = contact.postalCode || contact.address?.postalCode || null;
  // GHL custom fields for vehicle interest
  const customFields = contact.customFields || contact.customField || [];
  if (Array.isArray(customFields)) {
    for (const cf of customFields) {
      const key = (cf.key || cf.id || '').toLowerCase();
      if (key.includes('vehicle') || key.includes('make') || key.includes('model')) {
        lead.vehicles.push({ make: cf.value, type: 'wanted' });
      }
    }
  }
  lead.advisor = contact.assignedTo ? { name: contact.assignedTo } : null;
  lead.consentDate = contact.dateAdded || new Date().toISOString();
  lead.unsubscribeAll = contact.dnd || false;
  lead.unsubscribeSms = contact.dndSettings?.SMS?.status === 'active' || false;
  lead.unsubscribeEmail = contact.dndSettings?.Email?.status === 'active' || false;
} else {
  // Default: Activix
  lead.id = body.id || null;
  lead.firstName = body.first_name || null;
  lead.lastName = body.last_name || null;
  const emailArr = body.emails || [];
  lead.email = emailArr[0]?.address || emailArr[0]?.email || body.email || null;
  const phoneArr = body.phones || [];
  lead.phone = phoneArr[0]?.number || phoneArr[0]?.phone || body.phone || null;
  lead.phones = phoneArr;
  lead.emails = emailArr;
  lead.locale = body.locale || null;
  lead.source = body.source || null;
  lead.type = body.type || null;
  lead.postalCode = body.postal_code || body.address?.postal_code || null;
  lead.vehicles = body.vehicles || [];
  lead.advisor = body.advisor ? { name: `${body.advisor.first_name || ''} ${body.advisor.last_name || ''}`.trim(), id: body.advisor.id } : null;
  lead.consentType = body.consent_type || 'implied';
  lead.consentDate = body.consent_date || body.created_at || null;
  lead.unsubscribeAll = !!body.unsubscribe_all_date;
  lead.unsubscribeSms = !!body.unsubscribe_sms_date;
  lead.unsubscribeEmail = !!body.unsubscribe_email_date;
}

return [{ json: lead }];

// Detects en-CA or fr-CA from normalized lead data
// Priority: 1) locale field, 2) Quebec area codes, 3) Quebec postal code prefixes, 4) default en-CA

const lead = $input.first().json;
const QUEBEC_AREA_CODES = ['418', '438', '450', '514', '579', '581', '819', '873'];
const QUEBEC_POSTAL_PREFIXES = ['G', 'H', 'J'];

function detectLanguage(lead) {
  if (lead.locale) {
    const locale = lead.locale.toLowerCase();
    if (locale.startsWith('fr')) return 'fr-CA';
    if (locale.startsWith('en')) return 'en-CA';
  }
  // Check phones array
  const phones = lead.phones || [];
  for (const phone of phones) {
    const number = (phone.number || phone.phone || '').replace(/[^0-9]/g, '');
    let areaCode = '';
    if (number.length === 11 && number.startsWith('1')) areaCode = number.substring(1, 4);
    else if (number.length === 10) areaCode = number.substring(0, 3);
    if (QUEBEC_AREA_CODES.includes(areaCode)) return 'fr-CA';
  }
  // Check single phone field
  if (lead.phone) {
    const number = lead.phone.replace(/[^0-9]/g, '');
    let areaCode = '';
    if (number.length === 11 && number.startsWith('1')) areaCode = number.substring(1, 4);
    else if (number.length === 10) areaCode = number.substring(0, 3);
    if (QUEBEC_AREA_CODES.includes(areaCode)) return 'fr-CA';
  }
  const postalCode = lead.postalCode || '';
  if (postalCode && QUEBEC_POSTAL_PREFIXES.includes(postalCode.charAt(0).toUpperCase())) return 'fr-CA';
  return 'en-CA';
}

return [{ json: { ...lead, _locale: detectLanguage(lead) } }];

// CASL compliance pre-flight using normalized lead fields
const lead = $input.first().json;
const message = lead._message || '';
const now = new Date();
const failures = [];
let pass = true;

// 1. CASL consent check
const consentDate = lead.consentDate ? new Date(lead.consentDate) : null;
const consentType = lead.consentType || 'implied';
if (consentType === 'implied' && consentDate) {
  const sixMonthsLater = new Date(consentDate);
  sixMonthsLater.setMonth(sixMonthsLater.getMonth() + 6);
  if (now > sixMonthsLater) { failures.push('CASL: Implied consent expired (>6 months)'); pass = false; }
}

// 2. Opt-out check
if (lead.unsubscribeAll) { failures.push('Opt-out: Lead has unsubscribed from all communications'); pass = false; }
if (lead.unsubscribeSms) { failures.push('Opt-out: Lead has unsubscribed from SMS'); pass = false; }
if (lead.unsubscribeEmail) { failures.push('Opt-out: Lead has unsubscribed from email'); pass = false; }

// 3. Content validation — forbidden financial language
const FORBIDDEN_PATTERNS = [
  /\$\d+[\s/]*(per|a|\/)\s*month/i, /monthly\s*payment/i, /paiement\s*mensuel/i,
  /\d+(\.\d+)?\s*%\s*(apr|interest|taux|interet)/i, /interest\s*rate/i, /taux\s*d'interet/i,
  /financ(ing|ement)\s*(term|option|rate|taux)/i, /credit\s*score/i, /cote\s*de\s*credit/i,
  /insurance\s*(rate|cost|premium)/i, /assurance\s*(taux|cout|prime)/i,
  /(?:we'?ll|I'?ll|can)\s*beat\s*(any|the|their)/i, /guaranteed\s*approv/i, /approbation\s*garantie/i,
];
for (const pattern of FORBIDDEN_PATTERNS) {
  if (pattern.test(message)) { failures.push(`Content violation: ${pattern.source}`); pass = false; }
}

// 4. Message exists
if (!message || message.trim().length === 0) { failures.push('No message generated'); pass = false; }

return [{ json: { ...lead, _compliancePass: pass, _complianceFailures: failures, _complianceCheckedAt: now.toISOString() } }];

// Send SMS via configured messaging provider (Twilio or GHL)
const msgProvider = $env.MESSAGING_PROVIDER || 'twilio';
const lead = $input.first().json;
const locale = (lead.locale || 'en-CA').startsWith('fr') ? 'fr-CA' : 'en-CA';
const dealershipName = $env.DEALERSHIP_NAME || 'Our Dealership';
const dealershipPhone = $env.DEALERSHIP_PHONE || $env.TWILIO_FROM_NUMBER || '';
const optOutText = locale === 'fr-CA'
  ? `Répondez STOP pour vous désabonner. ${dealershipName} | ${dealershipPhone}`
  : `Reply STOP to unsubscribe. ${dealershipName} | ${dealershipPhone}`;
const message = (lead._message || '') + (lead._message ? '\n\n' + optOutText : '');
const recipientPhone = lead.phone || '';

let sendResult = { success: false, provider: msgProvider, error: null, messageId: null };

try {
  if (!recipientPhone) throw new Error('No phone number available for SMS');
  if (!message) throw new Error('No message to send');

  if (msgProvider === 'ghl') {
    // GHL Conversations API
    const GHL_API_KEY = $env.GHL_API_KEY || '';
    const GHL_LOCATION_ID = $env.GHL_LOCATION_ID || '';
    const contactId = lead.id;
    if (!contactId) throw new Error('No GHL contact ID for messaging');

    const response = await fetch('https://services.leadconnectorhq.com/conversations/messages', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${GHL_API_KEY}`,
        'Version': '2021-07-28',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        type: 'SMS',
        contactId: contactId,
        message: message,
      }),
    });
    const result = await response.json();
    if (response.ok) {
      sendResult = { success: true, provider: 'ghl', messageId: result.messageId || result.id || 'sent', error: null };
    } else {
      throw new Error(result.message || `GHL error: ${response.status}`);
    }
  } else {
    // Default: Twilio
    const TWILIO_ACCOUNT_SID = $env.TWILIO_ACCOUNT_SID || '';
    const TWILIO_AUTH_TOKEN = $env.TWILIO_AUTH_TOKEN || '';
    const TWILIO_FROM_NUMBER = $env.TWILIO_FROM_NUMBER || '';
    const twilioUrl = `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_ACCOUNT_SID}/Messages.json`;
    const body = new URLSearchParams({ To: recipientPhone, From: TWILIO_FROM_NUMBER, Body: message });
    const response = await fetch(twilioUrl, {
      method: 'POST',
      headers: { 'Authorization': 'Basic ' + btoa(`${TWILIO_ACCOUNT_SID}:${TWILIO_AUTH_TOKEN}`), 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });
    const result = await response.json();
    if (response.ok) {
      sendResult = { success: true, provider: 'twilio', messageId: result.sid, error: null };
    } else {
      throw new Error(result.message || `Twilio error: ${response.status}`);
    }
  }
} catch (err) {
  sendResult = { success: false, provider: msgProvider, error: err.message, messageId: null };
}

return [{ json: { ...lead, _smsResult: sendResult } }];

// Update CRM lead status after outreach — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';
const lead = $input.first().json;

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
let updateResult = { success: false, error: null };

try {
  if (provider === 'ghl') {
    // Update GHL contact
    const response = await fetch(`${config.baseUrl}/contacts/${lead.id}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({
        tags: [...(lead._raw?.tags || []), 'nexus-contacted', 'auto-response-sent'],
        customFields: [{ key: 'last_nexus_action', value: 'instant_response' }, { key: 'last_contact_date', value: new Date().toISOString() }],
      }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`GHL update error: ${response.status} ${errText}`); }
  } else {
    // Default: Activix PUT /v2/leads/:id
    const response = await fetch(`${config.baseUrl}/leads/${lead.id}`, {
      method: 'PUT',
      headers: config.headers,
      body: JSON.stringify({ result: 'attempted' }),
    });
    if (response.ok) updateResult = { success: true, error: null };
    else { const errText = await response.text(); throw new Error(`Activix update error: ${response.status} ${errText}`); }
  }
} catch (err) {
  updateResult = { success: false, error: err.message };
}

return [{ json: { ...lead, _crmUpdateResult: updateResult } }];
